def factorial(n):
    # Base case
    if n == 0 or n == 1:
        return 1
    # Recursive case
    else:
        return n * factorial(n - 1)

# Example: factorial(5) = 5 * 4 * 3 * 2 * 1 = 120

def fibonacci(n):
    # Base cases
    if n <= 0:
        return 0
    if n == 1:
        return 1
    # Recursive case - two recursive calls
    else:
        return fibonacci(n - 1) + fibonacci(n - 2)

# Example: fibonacci(5) = 5 (sequence: 0,1,1,2,3,5)

def binary_search(arr, target, low, high):
    # Base case: element not found
    if low > high:
        return -1

    mid = (low + high) // 2

    # Base case: element found
    if arr[mid] == target:
        return mid
    # Recursive case: search left or right half
    elif arr[mid] > target:
        return binary_search(arr, target, low, mid - 1)
    else:
        return binary_search(arr, target, mid + 1, high)

# Usage: binary_search([1,2,3,4,5], 3, 0, 4) returns 2
